<template>
  <div class="convert-ppt-to-image">
    <form
      class="formUpload"
      enctype="multipart/form-data"
      action="POST"
      @submit.prevent="uploadFormData"
    >
      <!-- <input type="hidden" name="_csrf" value="" /> -->
      <label
        >File:
        <input
          type="file"
          name="ppt"
          accept="application/vnd.ms-powerpoint,
          application/vnd.openxmlformats-officedocument.presentationml.presentation"
          @change="onFileChange"
      /></label>
      <input type="submit" value="submit" />
    </form>
    <h1>{{ message }}</h1>
  </div>
</template>

<script>
import { fileService } from '../services'
export default {
  name: 'ConvertPptToImage',
  data() {
    return {
      pptfile: null,
      message: '',
      images: null,
    }
  },
  methods: {
    onFileChange(e) {
      let files = e.target.files || e.dataTransfer.files
      if (!files.length) return
      this.pptfile = files[0]
      this.message = ''
      console.log(this.pptfile)
    },
    uploadFormData() {
      console.log('uploadFormData')
      if (!this.pptfile) return
      const formData = new FormData()
      const option = {
        headers: {
          'Content-Type': 'multipart/form-data',
          'Access-Control-Allow-Origin': '*',
        },
      }
      console.log(this.pttfile)
      formData.append('type', 'ppt')
      formData.append('ppt', this.pptfile, this.pptfile.name)
      // const vm = this
      fileService
        .upload(formData, option)
        .then(res => {
          console.log(res.data)
          this.images = {
            list: res.data.imagesData.images,
            source: res.data.imagesData.source,
          }
          this.message = res.data.message
        })
        .catch(err => {
          this.message = err
        })
    },
  },
}
</script>
