<template>
  <div class="convertor">
    <h1>Convert to ppt</h1>
    <convert-ppt-to-image></convert-ppt-to-image>
    <div class="container">
      <div class="row">
        <div class="col">
          <div class="form-group">
            <button @click.stop="loadDirList('ppt')">loadDirList</button>
            <label for="pptDirSelect">PPT Dir Select</label>
            <select
              id="pptDirSelect"
              v-model="selectedPptDirName"
              class="form-control"
              @change="handleDirNameSelected($event)"
            >
              <template v-for="(dirName, index) in pptDirList">
                <option :key="index" :value="dirName">{{ dirName }}</option>
              </template>
            </select>
          </div>
        </div>
        <div v-if="pptDirList.length > 0" class="col">
          <div class="form-group">
            <label for="pptImageSelect">PPT image Select</label>
            <select
              id="pptImageSelect"
              v-model="selectedPptImageName"
              class="form-control"
              @change="handleFileNameSelected($event)"
            >
              <template v-for="(imageName, index) in pptImageList">
                <option :key="index" :value="imageName">{{ imageName }}</option>
              </template>
            </select>
          </div>
        </div>
      </div>
      <div class="row">
        <template v-for="(image, index) in images">
          <div :key="index" class="col">
            {{ image }}
          </div>
        </template>
        <img ref="testImage" />
      </div>
    </div>
  </div>
</template>

<script>
import ConvertPptToImage from '@/components/ConvertPptToImage.vue'
import { fileService } from '@/services/api'
export default {
  components: {
    ConvertPptToImage,
  },
  data() {
    return {
      pptfile: null,
      message: '',
      images: [],
      pptDirList: [],
      selectedPptDirName: '',
      pptImageList: [],
      selectedPptImageName: '',
    }
  },
  methods: {
    handleDirNameSelected(event) {
      console.log('handleDirNameSelected', event)
      this.loadPptImageList()
    },
    handleFileNameSelected(event) {
      console.log('handleFileNameSelected', event)
      console.log(this.selectedPptDirName, this.selectedPptImageName)
      this.loadImagebyName(this.selectedPptDirName, this.selectedPptImageName)
    },
    loadImagebyName(dirName, imageName) {
      console.log('loadImagebyName', { dirName, imageName })
      fileService
        .getFile('ppt', dirName, imageName)
        .then(res => {
          this.$refs.testImage.src = `data:image/png;base64,${res.data}`
        })
        .catch(error => {
          console.log(error)
        })
    },
    loadDirList(dirName) {
      console.log('loadDirList:dirName =', dirName)
      fileService
        .getDirList(dirName)
        .then(res => {
          console.log('getDirList:res=', res)
          this.pptDirList = res.data.dirList
        })
        .catch(error => {
          console.log('getDirList:error=', error)
        })
    },
    loadPptImageList() {
      console.log('loadPptImageList', this.selectedPptDirName)
      const targetTypes = ['png', 'jpg', 'jpeg']
      fileService
        .getFileList('ppt', this.selectedPptDirName)
        .then(res => {
          console.log('getFileList:res=', res)
          this.pptImageList = res.data.fileList.filter(filename => {
            const [type] = filename.split('.').slice(-1)
            return targetTypes.includes(type.toLowerCase())
          })
        })
        .catch(error => {
          console.log('getFileList:error=', error)
        })
    },
  },
}
</script>

<style lang="scss" scoped>
.convertor {
  h1,
  form {
    text-align: center;
  }
}
</style>
